// ChatMessageModal.jsx - Remove all socket code
import React, { useState, useEffect, useRef } from "react";
import { X, Send } from "lucide-react";
import {
    getMessages,
    sendMessage,
    getUserConversations,
} from "../../../api/chatApi";
import axios from "axios";
import { API_BASE_URL } from "../../../config/config";

export default function ChatMessageModal({ onClose, currentUser }) {
    const [messages, setMessages] = useState([]);
    const [messageInput, setMessageInput] = useState("");
    const [conversation, setConversation] = useState(null);
    const [selectedUser, setSelectedUser] = useState(null);
    const [conversationsList, setConversationsList] = useState([]);
    const [loading, setLoading] = useState(false);
    const messagesEndRef = useRef(null);
    const API_URL = `${API_BASE_URL}api/user/chatmessage`;

    // Load all conversations on mount
    useEffect(() => {
        if (currentUser?.id) {
            loadConversations();
        }
    }, []);

    // Load user's conversations
    const loadConversations = async () => {
        setLoading(true);
        try {
            const response = await getUserConversations(currentUser?.type, currentUser?.id);
            if (response.success) {
                setConversationsList(response.conversations);
                // Auto-select first conversation if exists
                if (response.conversations.length > 0 && !selectedUser) {
                    const firstConv = response.conversations[0];
                    setSelectedUser({
                        id: firstConv.other_user_id,
                        type: firstConv.other_user_type,
                        name: firstConv.other_user?.name || "User",
                        role: firstConv.other_user_type,
                        avatar: "/default-avatar.png"
                    });
                    await getOrCreateConversationWithUser(firstConv.other_user_id, firstConv.other_user_type);
                }
            }
        } catch (error) {
            console.error("Error loading conversations:", error);
        } finally {
            setLoading(false);
        }
    };

    // Get or create conversation with selected user
    const getOrCreateConversationWithUser = async (userId, userType) => {
        try {
            const response = await axios.post(`${API_URL}/get_or_create_conversation`,
                {
                    participant1_type: currentUser?.type,
                    participant1_id: currentUser?.id,
                    participant2_type: userType,
                    participant2_id: userId
                },
                {
                    headers: { "Content-Type": "application/json" },
                }
            );

            if (response.data.success) {
                setConversation(response.data.conversation);
                loadMessages(response.data.conversation.conversation_id);
            }
        } catch (error) {
            console.error("❌ Error:", error.response?.data || error.message);
        }
    };

    // Handle user selection from left menu
    const handleSelectUser = async (user) => {
        setSelectedUser(user);
        await getOrCreateConversationWithUser(user.id, user.type);
    };

    const loadMessages = async (conversationId) => {
        const response = await getMessages(conversationId, currentUser.id, currentUser.type);
        if (response.success) {
            setMessages(response.messages);
            scrollToBottom();
        }
    };

    const handleSendMessage = async () => {
        if (!messageInput.trim() || !conversation) return;

        const newMsg = {
            id: Date.now(),
            message: messageInput,
            isMe: true,
            created_at: new Date(),
            sender_name: currentUser.name
        };

        setMessages(prev => [...prev, newMsg]);
        setMessageInput("");
        scrollToBottom();

        await sendMessage(
            conversation.conversation_id,
            currentUser.type, currentUser.id,
            selectedUser.type, selectedUser.id,
            messageInput
        );
    };

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    const getRoleColor = (role) => {
        if (role === "company") return "#f44336";
        if (role === "investor") return "#4caf50";
        if (role === "admin") return "#9c27b0";
        return "#6c757d";
    };

    return (
        <div style={styles.modalOverlay}>
            <div style={styles.modalContainer}>
                {/* Left Sidebar - User List */}
                <div style={styles.sidebar}>
                    <div style={styles.sidebarHeader}>
                        <h5>Messages</h5>
                        <button onClick={onClose} style={styles.closeBtn}>
                            <X size={20} />
                        </button>
                    </div>
                    <div style={styles.userList}>
                        {loading ? (
                            <div style={styles.loading}>Loading conversations...</div>
                        ) : conversationsList.length === 0 ? (
                            <div style={styles.emptyState}>
                                <p>No messages yet</p>
                            </div>
                        ) : (
                            conversationsList.map((conv) => (
                                <div
                                    key={conv.id}
                                    onClick={() => handleSelectUser({
                                        id: conv.other_user_id,
                                        type: conv.other_user_type,
                                        name: conv.other_user?.name || "User",
                                        role: conv.other_user_type
                                    })}
                                    style={{
                                        ...styles.userItem,
                                        backgroundColor: selectedUser?.id === conv.other_user_id ? "#fff" : "transparent",
                                        borderLeft: selectedUser?.id === conv.other_user_id ? "3px solid #ff3e43" : "3px solid transparent"
                                    }}
                                >
                                    <div style={styles.userAvatar}>
                                        <div style={styles.avatarPlaceholder}>
                                            {conv.other_user?.name?.charAt(0) || "U"}
                                        </div>
                                    </div>
                                    <div style={styles.userInfo}>
                                        <div style={styles.userName}>
                                            <strong>{conv.other_user?.name}</strong>
                                        </div>
                                        <div style={styles.userRole}>
                                            <span style={{
                                                ...styles.roleBadgeSmall,
                                                backgroundColor: getRoleColor(conv.other_user_type)
                                            }}>
                                                {conv.other_user_type}
                                            </span>
                                        </div>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                </div>

                {/* Right Side - Chat Area */}
                <div style={styles.chatArea}>
                    {selectedUser ? (
                        <>
                            <div style={styles.chatHeader}>
                                <div style={styles.avatarPlaceholder}>
                                    {selectedUser?.name?.charAt(0) || "U"}
                                </div>
                                <div>
                                    <h6>{selectedUser?.name}</h6>
                                    <span style={{
                                        ...styles.roleBadge,
                                        backgroundColor: getRoleColor(selectedUser?.type)
                                    }}>
                                        {selectedUser?.role || selectedUser?.type}
                                    </span>
                                </div>
                            </div>

                            <div style={styles.messagesArea}>
                                {messages.length === 0 ? (
                                    <div style={styles.noMessagesYet}>
                                        <p>No messages yet</p>
                                    </div>
                                ) : (
                                    messages.map((msg, idx) => (
                                        <div
                                            key={msg.id || idx}
                                            style={{
                                                ...styles.messageRow,
                                                justifyContent: msg.sender_id === currentUser?.id ? "flex-end" : "flex-start"
                                            }}
                                        >
                                            <div style={{
                                                ...styles.messageBubble,
                                                backgroundColor: msg.sender_id === currentUser?.id ? "#ff3e43" : "#f1f3f4",
                                                color: msg.sender_id === currentUser?.id ? "#fff" : "#202124"
                                            }}>
                                                <p>{msg.message}</p>
                                                <span style={styles.messageTime}>
                                                    {new Date(msg.created_at).toLocaleTimeString()}
                                                </span>
                                            </div>
                                        </div>
                                    ))
                                )}
                                <div ref={messagesEndRef} />
                            </div>

                            <div style={styles.inputArea}>
                                <input
                                    type="text"
                                    placeholder="Type your message..."
                                    value={messageInput}
                                    onChange={(e) => setMessageInput(e.target.value)}
                                    onKeyPress={(e) => e.key === "Enter" && handleSendMessage()}
                                    style={styles.input}
                                />
                                <button onClick={handleSendMessage} style={styles.sendBtn}>
                                    <Send size={18} color="#fff" />
                                </button>
                            </div>
                        </>
                    ) : (
                        <div style={styles.noChatSelected}>
                            <p>Select a conversation to start chatting</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

const styles = {
    modalOverlay: {
        position: "fixed",
        top: 0, left: 0, right: 0, bottom: 0,
        backgroundColor: "rgba(0,0,0,0.7)",
        zIndex: 99999,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        backdropFilter: "blur(8px)"
    },
    modalContainer: {
        width: "90%",
        maxWidth: "1200px",
        height: "80vh",
        backgroundColor: "#fff",
        borderRadius: "16px",
        display: "flex",
        overflow: "hidden",
        boxShadow: "0 20px 60px rgba(0,0,0,0.3)"
    },
    sidebar: {
        width: "320px",
        borderRight: "1px solid #e9ecef",
        display: "flex",
        flexDirection: "column",
        backgroundColor: "#f8f9fa"
    },
    sidebarHeader: {
        padding: "20px",
        borderBottom: "1px solid #e9ecef",
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center"
    },
    closeBtn: {
        background: "none",
        border: "none",
        cursor: "pointer",
        padding: "4px"
    },
    userList: {
        flex: 1,
        overflowY: "auto"
    },
    userItem: {
        display: "flex",
        alignItems: "center",
        padding: "15px 20px",
        cursor: "pointer",
        borderBottom: "1px solid #e9ecef",
        transition: "all 0.2s"
    },
    userAvatar: {
        marginRight: "12px"
    },
    avatarPlaceholder: {
        width: "48px",
        height: "48px",
        borderRadius: "50%",
        backgroundColor: "#ff3e43",
        color: "#fff",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        fontWeight: "bold",
        fontSize: "18px"
    },
    userInfo: {
        flex: 1
    },
    userName: {
        marginBottom: "4px"
    },
    userRole: {
        display: "flex",
        alignItems: "center",
        gap: "6px"
    },
    roleBadgeSmall: {
        fontSize: "9px",
        padding: "2px 6px",
        borderRadius: "4px",
        color: "#fff"
    },
    chatArea: {
        flex: 1,
        display: "flex",
        flexDirection: "column"
    },
    chatHeader: {
        padding: "20px",
        borderBottom: "1px solid #e9ecef",
        display: "flex",
        alignItems: "center",
        gap: "12px"
    },
    roleBadge: {
        fontSize: "11px",
        padding: "2px 8px",
        borderRadius: "4px",
        color: "#fff",
        display: "inline-block"
    },
    messagesArea: {
        flex: 1,
        overflowY: "auto",
        padding: "20px",
        display: "flex",
        flexDirection: "column",
        gap: "12px",
        backgroundColor: "#f8f9fa"
    },
    noMessagesYet: {
        textAlign: "center",
        padding: "40px",
        color: "#6c757d"
    },
    messageRow: {
        display: "flex"
    },
    messageBubble: {
        maxWidth: "70%",
        padding: "10px 14px",
        borderRadius: "12px",
        boxShadow: "0 1px 2px rgba(0,0,0,0.1)"
    },
    messageTime: {
        fontSize: "10px",
        color: "rgba(0,0,0,0.5)",
        display: "block",
        marginTop: "4px"
    },
    inputArea: {
        padding: "20px",
        borderTop: "1px solid #e9ecef",
        display: "flex",
        gap: "12px",
        backgroundColor: "#fff"
    },
    input: {
        flex: 1,
        padding: "10px 16px",
        border: "1px solid #ddd",
        borderRadius: "24px",
        outline: "none",
        fontSize: "14px"
    },
    sendBtn: {
        backgroundColor: "#ff3e43",
        border: "none",
        borderRadius: "50%",
        width: "40px",
        height: "40px",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        cursor: "pointer"
    },
    loading: {
        padding: "20px",
        textAlign: "center",
        color: "#6c757d"
    },
    emptyState: {
        padding: "40px 20px",
        textAlign: "center",
        color: "#6c757d"
    },
    noChatSelected: {
        flex: 1,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        color: "#6c757d",
        textAlign: "center"
    }
};